    leadCounsel: "Pending (multiple filers)",
    keyPrecedent: "In re Anthem Data Breach Litig.",
    tags: ["Change Healthcare", "UnitedHealth", "ransomware", "health data", "ALPHV", "BlackCat", "MDL", "2024"],
